var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"아아, 이게 어떻게 된 일일까! 조디악 나이츠가 파죽지세로 밀어붙이고 있다구!!","JPN":"ああっ、これはどういうことだ！　ゾディアックナイツが破竹の勢いで押し寄せてるよ！！","ENG":"Oh? What's going on here?! The Zodiac Knights are running their opponents to a corner with unstoppable force!","TWN":"喂！就算你再怎麼想贏，也不應該用炸藥吧！好奸詐！"},"stage":{"bg":"HELI_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"기습도, 속임수도 없는 정공법!! 하지만 빈틈이 보이지 않는다!!","JPN":"奇襲も、騙しもない正攻法！　でも隙が見えない！！","ENG":"No ambushes, no trickery! Just a full-on attack! But their attacks are airtight!","TWN":"奸詐？那換成這個呢？"},"stage":{"bg":"HELI_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"과연 조디악 나이츠!! 이번 경기에서 우승하여 불명예스러운……!","JPN":"果たして、ゾディアックナイツ！！　この試合で優勝して、不名誉な……！","ENG":"Incredible, Zodiac Knights!! By winning this match, maybe they'll be able to–!","TWN":"十二宮騎士！！能否在此次比賽獲勝，洗刷不光彩的……"},"stage":{"bg":"HELI_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"피오네 언니 힘내세요!!","JPN":"フィオネさん、頑張って！！","ENG":"Give it your all, Fione!!","TWN":"菲奧尼姊姊加油！！"},"stage":{"bg":"HELI_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"리브 언니도!! 한솔 경도!! 모두 모두 파이팅이에요!! 파이팅!!","JPN":"リブさんも！　ヤガミ卿も！！　みんなみんなファイトです！！　ファイト！！","ENG":"You too, Liv and Sir Hansol!! Don't stop! I'm rooting for you all!!","TWN":"這是薄荷煙霧彈，這是我從G1某間咖啡廳的菜單上得到的靈感。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"우린 할 수 있어요!","JPN":"私たちならできます！","ENG":"We can do this!","TWN":"呃啊啊！煙霧好刺激，眼睛好痛！"},"stage":{"bg":"HELI_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"대박… 조디악 나이츠라는 녀석들, 생각보다 훨씬 잘 싸우는데?","JPN":"すごい……ゾディアックナイツってやつら、思ったよりうまいな！","ENG":"Whoa... these Zodiac Knights are way tougher than I thought.","TWN":"哇塞……十二宮騎士團這些傢伙，打得比想像中要好得多啊？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"미치 말대로 정공법 스타일이라 그런지 보는 맛이 있어. 나도 모르게 응원하게 돼…!!","JPN":"ミッチーの言う通り正攻法スタイルだから見てて楽しいし、ついつい応援したくなる……！！","ENG":"Just like Mitchie said, their straightforward style makes them exciting to watch. I can't help but root for them...!!","TWN":"正如米琪所說，正攻法風格確實很有看頭。不知不覺就會為他們加油…！！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"힘내라! 조디악 나이츠-!!","JPN":"がんばれ！　ゾディアックナイツ！！","ENG":"Let's go, Zodiac Knights!!","TWN":"加油！十二宮騎士團-！！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"흐응~. 피오네도 제법이네. 못 본 사이에 엔터테이너 기질이 생겼어.","JPN":"ふーん……フィオネもなかなかやるわね。ちょっと見ない間にエンタテイナーの才能が芽生えたのかしら。","ENG":"Hmm...? Fione's not bad. Looks like she picked up some stage presence while I was away.","TWN":"嗯~。菲奧尼也不錯嘛。一陣子沒見，居然有了娛樂精神。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"원래라면 적당히 구경만 할 생각이었지만… 이런 상황이라면 얘기가 다르지.","JPN":"本当は少し見て帰ろうと思ってたけれど……この状況だと、話は違ってくるわね。","ENG":"I was just planning to watch from the sidelines, but now... this changes things.","TWN":"本來只是打算適當看看而已……但這種情況下，事情就不一樣了。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"오지만디아스? 예정된 스케줄은 없는데 어딜 가시는 거죠?","JPN":"オジマンディアス？　この後の予定は特にないと思いますが……どちらへ？","ENG":"Ozymandias? You're not scheduled for anything. Where are you going?","TWN":"奧茲曼迪亞斯？你要去哪裡？"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"잠깐 바람 쐬러~. 직원분도 심심하면 같이 갈래?","JPN":"ちょっと風に当たりたくて～。あなたも暇なら一緒に行く？","ENG":"Just stepping out for a breather. Wanna tag along if you're bored?","TWN":"稍微出去透透氣～大家們如果無聊的話，要不要一起去？"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"……아직 건틀렛이 진행 중이니 눈에 띄는 행동은 삼가주세요, 챔피언.","JPN":"……まだガントレットが進行中なので、目立つ行動は控えてください、チャンピオン。","ENG":"...The Gauntlet is still in progress. Please avoid drawing attention, Champion.","TWN":"……聖鎧還在進行中，請避免引人注目的行動，冠軍。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"너무하네~. 나 의외로 얌전하다는 소리 자주 들은 여자다?","JPN":"ひどいわね～。私、意外と大人しいってよく言われるのよ？","ENG":"Aw, that's harsh. I've been told I'm surprisingly well-behaved, you know?","TWN":"太過分了～我可是經常被說是意外地很乖的女生喔？"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그냥 적당히 놀다 올 테니 신경 쓰지 말라고.","JPN":"ちょっと遊んですぐ帰ってくるから、心配しないでちょうだい。","ENG":"I'm just gonna have a little fun. Don't worry about it.","TWN":"我只是去玩玩而已，不用擔心。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"아아! 여기서 스피어헤드 대열을 통한 진형 붕괴 전략! 유리한 전황에 쐐기를 박으려는 것인가?","JPN":"ああ！　ここでスピアヘッド隊列を利用した陣形崩壊戦略！　有利な戦況を固めるつもりか？","ENG":"Ah! They're shifting into a spearhead formation! Are they trying to seal the deal with this push?","TWN":"啊啊！這裡透過先鋒隊陣列的陣型崩潰戰略！是想在有利的戰況中釘下楔子嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"상대 함선에 키스하던 패기는 어디로 갔어? 좀 더 근성을 보여라, 카나리아 스쿼드!","JPN":"相手の艦船にキスをしていた覇気はどこへ行った！　もっと根性を見せろ、カナリア・スクワッド！","ENG":"Where's that fearless energy from when they were ramming enemy ships?! Come on, show some guts, Canary Squad!","TWN":"曾經敢於挑戰敵艦的勇氣去哪了？展現出更多的毅力吧，金絲雀小隊！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"아니지. 핵심 전력이 우위에 있으니 거기선 피해를 감수하더라도 게릴라가 옳아.","JPN":"ううん、核心戦力が優位にある分、そこはリスクを負ってでもゲリラで行くほうが正解。","ENG":"No, that's not it. With their main force in the lead, they should be running guerrilla tactics even if it means taking some hits.","TWN":"不對。既然核心戰力占優，即使在那裡承受損失，遊擊戰也是正確的選擇。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"캐리였다면 진작에 끝냈을 텐데, 아군 쪽 피해까지 고려하면서 싸우고 있잖아?","JPN":"ケリーだったらとっくに終わらせたでしょうに。味方の被害を意識しすぎるのが丸見えよ。","ENG":"If it were Carrie out there, she'd have finished it already. But they're holding back to avoid friendly losses.","TWN":"如果是凱莉的話早就結束了吧，她還在考慮我方的損失進行戰鬥呢？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"기사단다운 방식이지만… 건틀렛에서는 악수지. 상대가 루이즈네라면, 더더욱.","JPN":"騎士団らしいやり方だけど……ガントレットでは悪手ね。相手がルイーズたちならなおさら。","ENG":"That's very knightly of them... but in the Gauntlet? That's a bad move. Especially against someone like Louisé.","TWN":"雖然是騎士團的方式……但在聖鎧中就是握手。如果對手是路易士，那就更是如此。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"피오네한테는 미안하지만 결과가 보이기 시작했는걸?","JPN":"フィオネには悪いけど、そろそろ結果が見えてきたわ。","ENG":"Sorry, Fione, but I can already see how this ends.","TWN":"雖然對菲奧尼感到抱歉，但結果已經開始顯現了呢？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"……응?","JPN":"……うん？","ENG":"...Hmm?","TWN":"……嗯?"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"하아~. 이놈의 인기. 하여간 파파라치들은 질리지도 않나 봐?","JPN":"はあ～。人気者は辛いわ。パパラッチも懲りずによくやるわ。","ENG":"Ugh, not again. Can't the paparazzi take a day off?","TWN":"唉～這該死的人氣。那些狗仔隊真是沒完沒了嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};